@* Displays a single task as a card with move-left/move-right buttons *@

<div class="card mb-2">
    <div class="card-body p-2">
        <h6 class="card-title mb-1">@Task.Title</h6>
        <p class="card-text mb-1 text-muted small">@Task.Assignee</p>
        <div class="d-flex justify-content-between align-items-center">
            <span class="badge @PriorityClass">@Task.Priority</span>
            <small class="text-muted">@Task.DueDate.ToString("MMM dd")</small>
        </div>
        <div class="d-flex justify-content-between mt-2">
            @if (ShowMoveLeft)
            {
                <button class="btn btn-outline-secondary btn-sm" @onclick="OnMoveLeft">← Move Left</button>
            }
            else
            {
                <span></span>
            }
            @if (ShowMoveRight)
            {
                <button class="btn btn-outline-secondary btn-sm" @onclick="OnMoveRight">Move Right →</button>
            }
        </div>
    </div>
</div>

@code {
    [Parameter, EditorRequired]
    public TaskItem Task { get; set; } = default!;

    [Parameter]
    public bool ShowMoveLeft { get; set; }

    [Parameter]
    public bool ShowMoveRight { get; set; }

    [Parameter]
    public EventCallback OnMoveLeft { get; set; }

    [Parameter]
    public EventCallback OnMoveRight { get; set; }

    private string PriorityClass => Task.Priority switch
    {
        "High" => "bg-danger",
        "Medium" => "bg-warning text-dark",
        "Low" => "bg-success",
        _ => "bg-secondary"
    };
}

@* Inline form for creating a new task within a column *@

<div class="card mb-2 border-primary">
    <div class="card-body p-2">
        <div class="mb-2">
            <input type="text" class="form-control form-control-sm" placeholder="Title"
                   @bind="title" @bind:event="oninput" />
        </div>
        <div class="mb-2">
            <input type="text" class="form-control form-control-sm" placeholder="Assignee"
                   @bind="assignee" @bind:event="oninput" />
        </div>
        <div class="mb-2">
            <select class="form-select form-select-sm" @bind="priority">
                <option value="High">High</option>
                <option value="Medium">Medium</option>
                <option value="Low">Low</option>
            </select>
        </div>
        <div class="mb-2">
            <input type="date" class="form-control form-control-sm" @bind="dueDate" />
        </div>
        <div class="d-flex gap-2">
            <button class="btn btn-primary btn-sm" @onclick="Save" disabled="@saving">
                @(saving ? "Saving…" : "Save")
            </button>
            <button class="btn btn-outline-secondary btn-sm" @onclick="Cancel" disabled="@saving">Cancel</button>
        </div>
        @if (!string.IsNullOrEmpty(error))
        {
            <div class="text-danger small mt-1">@error</div>
        }
    </div>
</div>

@code {
    [Parameter, EditorRequired]
    public EventCallback<TaskItem> OnTaskCreated { get; set; }

    [Parameter, EditorRequired]
    public EventCallback OnCancel { get; set; }

    [Parameter, EditorRequired]
    public string DefaultStatus { get; set; } = "";

    [Parameter, EditorRequired]
    public ITaskService TaskService { get; set; } = default!;

    private string title = "";
    private string assignee = "";
    private string priority = "Medium";
    private DateTime dueDate = DateTime.Today.AddDays(7);
    private bool saving;
    private string? error;

    private async Task Save()
    {
        if (string.IsNullOrWhiteSpace(title) || string.IsNullOrWhiteSpace(assignee))
        {
            error = "Title and assignee are required.";
            return;
        }

        saving = true;
        error = null;

        try
        {
            var created = await TaskService.CreateTaskAsync(title, assignee, priority, dueDate);
            // If the service doesn't assign the column status, wrap with correct status
            var task = created with { Status = DefaultStatus };
            await OnTaskCreated.InvokeAsync(task);
        }
        catch (Exception ex)
        {
            error = $"Failed to save: {ex.Message}";
        }
        finally
        {
            saving = false;
        }
    }

    private async Task Cancel()
    {
        await OnCancel.InvokeAsync();
    }
}

@* A single Kanban column: header with count, task cards, and inline add-task form *@

<div class="kanban-column d-flex flex-column">
    <div class="card">
        <div class="card-header d-flex justify-content-between align-items-center">
            <h5 class="mb-0">@ColumnName</h5>
            <span class="badge bg-secondary">@Tasks.Count</span>
        </div>
        <div class="card-body p-2" style="min-height: 200px; overflow-y: auto;">
            @foreach (var task in Tasks)
            {
                <TaskCard Task="task"
                          ShowMoveLeft="ShowLeftButton"
                          ShowMoveRight="ShowRightButton"
                          OnMoveLeft="() => MoveTask(task, LeftStatus!)"
                          OnMoveRight="() => MoveTask(task, RightStatus!)" />
            }

            @if (showForm)
            {
                <AddTaskForm DefaultStatus="@ColumnName"
                             TaskService="TaskService"
                             OnTaskCreated="HandleTaskCreated"
                             OnCancel="() => showForm = false" />
            }
        </div>
        <div class="card-footer p-2">
            <button class="btn btn-outline-primary btn-sm w-100" @onclick="() => showForm = true"
                    disabled="@showForm">
                + Add Task
            </button>
        </div>
    </div>
</div>

@code {
    [Parameter, EditorRequired]
    public string ColumnName { get; set; } = "";

    [Parameter, EditorRequired]
    public List<TaskItem> Tasks { get; set; } = new();

    [Parameter]
    public string? LeftStatus { get; set; }

    [Parameter]
    public string? RightStatus { get; set; }

    [Parameter, EditorRequired]
    public EventCallback<(int TaskId, string NewStatus)> OnMoveTask { get; set; }

    [Parameter, EditorRequired]
    public EventCallback<TaskItem> OnTaskCreated { get; set; }

    [Parameter, EditorRequired]
    public ITaskService TaskService { get; set; } = default!;

    private bool ShowLeftButton => LeftStatus is not null;
    private bool ShowRightButton => RightStatus is not null;

    private bool showForm;

    private async Task MoveTask(TaskItem task, string newStatus)
    {
        await OnMoveTask.InvokeAsync((task.Id, newStatus));
    }

    private async Task HandleTaskCreated(TaskItem task)
    {
        showForm = false;
        await OnTaskCreated.InvokeAsync(task);
    }
}

@* Summary stats bar: total tasks, count per column, overdue count *@

<div class="d-flex flex-wrap gap-3 mb-3">
    <div class="badge bg-primary fs-6 p-2">Total: @Tasks.Count</div>
    <div class="badge bg-info text-dark fs-6 p-2">To Do: @Tasks.Count(t => t.Status == "To Do")</div>
    <div class="badge bg-warning text-dark fs-6 p-2">In Progress: @Tasks.Count(t => t.Status == "In Progress")</div>
    <div class="badge bg-success fs-6 p-2">Done: @Tasks.Count(t => t.Status == "Done")</div>
    <div class="badge bg-danger fs-6 p-2">Overdue: @Tasks.Count(t => t.DueDate < DateTime.Today && t.Status != "Done")</div>
</div>

@code {
    [Parameter, EditorRequired]
    public List<TaskItem> Tasks { get; set; } = new();
}

@* Search bar for filtering tasks by title *@

<div class="mb-3">
    <input type="text" class="form-control" placeholder="Search tasks by title…"
           @bind="searchText" @bind:event="oninput" @bind:after="NotifyChanged" />
</div>

@code {
    [Parameter]
    public string SearchText { get; set; } = "";

    [Parameter]
    public EventCallback<string> SearchTextChanged { get; set; }

    private string searchText = "";

    protected override void OnParametersSet()
    {
        searchText = SearchText;
    }

    private async Task NotifyChanged()
    {
        await SearchTextChanged.InvokeAsync(searchText);
    }
}

