@page "/board"
@using sv_bb3ca65701f849e695b5efe99c79140e.Components.Board
@rendermode InteractiveServer
@inject ITaskService TaskService

<PageTitle>Kanban Board</PageTitle>

<h1 class="mb-3">Kanban Board</h1>

@if (loading)
{
    <div class="d-flex justify-content-center my-5">
        <div class="spinner-border text-primary" role="status">
            <span class="visually-hidden">Loading…</span>
        </div>
    </div>
}
else if (error is not null)
{
    <div class="alert alert-danger" role="alert">
        <strong>Error loading tasks:</strong> @error
        <button class="btn btn-outline-danger btn-sm ms-3" @onclick="LoadTasks">Retry</button>
    </div>
}
else
{
    <BoardSummaryBar Tasks="tasks" />

    <BoardSearchBar @bind-SearchText="searchText" />

    <div class="kanban-board d-flex gap-3">
        <KanbanColumn ColumnName="To Do"
                      Tasks="FilteredTasks("To Do")"
                      RightStatus="In Progress"
                      TaskService="TaskService"
                      OnMoveTask="HandleMoveTask"
                      OnTaskCreated="HandleTaskCreated" />

        <KanbanColumn ColumnName="In Progress"
                      Tasks="FilteredTasks("In Progress")"
                      LeftStatus="To Do"
                      RightStatus="Done"
                      TaskService="TaskService"
                      OnMoveTask="HandleMoveTask"
                      OnTaskCreated="HandleTaskCreated" />

        <KanbanColumn ColumnName="Done"
                      Tasks="FilteredTasks("Done")"
                      LeftStatus="In Progress"
                      TaskService="TaskService"
                      OnMoveTask="HandleMoveTask"
                      OnTaskCreated="HandleTaskCreated" />
    </div>
}

@code {
    private List<TaskItem> tasks = new();
    private string searchText = "";
    private bool loading = true;
    private string? error;

    protected override async Task OnInitializedAsync()
    {
        await LoadTasks();
    }

    private async Task LoadTasks()
    {
        loading = true;
        error = null;

        try
        {
            tasks = await TaskService.GetAllTasksAsync();
        }
        catch (Exception ex)
        {
            error = ex.Message;
        }
        finally
        {
            loading = false;
        }
    }

    private List<TaskItem> FilteredTasks(string status)
    {
        var filtered = tasks.Where(t => t.Status == status);

        if (!string.IsNullOrWhiteSpace(searchText))
        {
            filtered = filtered.Where(t =>
